using System;using System.Collections.Generic;using System.Collections.ObjectModel;using System.IO;using System.Linq;using System.Threading.Tasks;using Avalonia.Interactivity;using CommunityToolkit.Mvvm.ComponentModel;using CommunityToolkit.Mvvm.Input;using Control.Basic;using Framework.Common;using Framework.Utils.Helpers;using Menu.DevData;using Plugin.AppEnv;using Plugin.Log;namespace UniClient;public partial class HomeViewModel : UniViewModel{    public override void OnLoaded(object? sender, RoutedEventArgs e)    {        base.OnLoaded(sender, e);        if (GenTasks.Count <= 0)        {            LoadGenTasks();        }    }    private void LoadGenTasks()    {        string[] dirs = GetDirectories(Path.Combine(".", "templates"))   // root directory            .Concat(GetDirectories(Path.Combine(Global.Get<IAppEnv>().UserDataDir, "templates"))) // user directory            .ToArray();        foreach (string dir in dirs)        {            GenTask? task = LoadGenTask(dir);            if (null == task) { continue; }            task.OutputDir = Global.Get<IUserSetting>().GenTaskConfs.FirstOrDefault(x => x.TemplateDir.Equals(task.TemplateDir))?.OutputDir ?? @".\code_autogen";            GenTasks.Add(new GenTaskModel(task, View));        }                // refresh setting        Global.Get<IUserSetting>().GenTaskConfs.Clear();        foreach (GenTaskModel genTaskModel in GenTasks)        {            Global.Get<IUserSetting>().GenTaskConfs.Add(new GenTaskConf            {                TemplateDir = genTaskModel.TemplateDir,                OutputDir = genTaskModel.OutputDir            });        }        Global.Get<IUserSetting>().Save();    }    private string[] GetDirectories(string dir)    {        if (!Directory.Exists(dir))        {            return [];        }        return Directory.GetDirectories(dir);    }    private GenTask? LoadGenTask(string dir)    {        string taskConfPath = Path.Combine(dir, "GenTask.xml");        if (!File.Exists(taskConfPath))        {            return null;        }                GenTask task = ObjectHelper.FromXmlFile<GenTask>(taskConfPath);        task.TaskName = Path.GetFileName(dir);        task.TemplateDir = dir;        return task;    }        [ObservableProperty] private ObservableCollection<GenTaskModel> _genTasks = [];    [ObservableProperty] private string _logs = string.Empty;    [RelayCommand]    private async Task SystemSetting()    {        ConfirmDialogResult result = await ConfirmDialog.Show<SystemSettingDialog, SystemSettingDialogViewModel>();        if (!result.IsConfirmed || result.ReturnParameter is not SystemSettingModel systemSettingModel)        {            return;        }                systemSettingModel.ToUserSetting();        Global.Get<IUserSetting>().Save();    }    [RelayCommand]    private async Task Generate()    {        List<GenTaskModel> tasks = GenTasks.Where(x => x.ShouldGenerate).ToList();        if (tasks.Count <= 0)        {            await MessageDialog.Show("R_STR_SELECT_EMPTY_TASK_NOTICE");            return;        }        Logs = string.Empty;        foreach (GenTaskModel taskModel in tasks)        {            try            {                await PrintLog(ResourceHelper.FindResource<string>("R_STR_START_TO_RUN_TASK").Replace("#1", taskModel.TaskName));                await CodeGenerator.GenFile(taskModel.GetTask());                await PrintLog(ResourceHelper.FindResource<string>("R_STR_TASK_FINISHED").Replace("#1", taskModel.TaskName));            }            catch (Exception e)            {                await PrintLog(e.Message);                await PrintLog(e.StackTrace ?? string.Empty);            }        }    }    private async Task PrintLog(string log)    {        Global.Get<ILog>().Info(LogModule.PUBLIC, log);        await Task.Run(() =>        {            if (Logs.Length > 0)            {                Logs += Environment.NewLine;            }            Logs += $"[{DateTimeHelper.CurrentTime()}] {log}";        });    }}